from flask import Flask, render_template, request, redirect, url_for, session
import secrets  # For generating secure session keys

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)  # Generate a random secret key (VERY IMPORTANT!)

# Dummy user database (replace with a real database in a production environment)
users = {
    "user1": "password1",
    "user2": "password2"
}


@app.route("/", methods=["GET", "POST"])
def index():
    if "username" in session:
        return render_template("index.html", username=session["username"])  # User is logged in

    if request.method == "POST":
        username = request.form["username"]
        password = request.form["password"]

        if username in users and users[username] == password:
            session["username"] = username  # Store username in the session
            return redirect(url_for("index"))  # Redirect to the home page
        else:
            return render_template("index.html", error="Invalid username or password")

    return render_template("index.html", error=None)  # Show login form


@app.route("/logout")
def logout():
    session.pop("username", None)  # Remove username from the session
    return redirect(url_for("index"))  # Redirect to the login page


