    const bucket = new s3.Bucket(this, 'MyEncryptedBucket', {
      bucketName: 'my-encrypted-bucket-' + Math.floor(Math.random() * 1000), // Unique bucket name
      removalPolicy: cdk.RemovalPolicy.DESTROY, // Important for testing/cleanup
      autoDeleteObjects: true, // Delete objects when the bucket is deleted
