import os
import fnmatch

def list_files(directory="."):
    """Lists all files and directories in the given directory."""
    try:
        files = os.listdir(directory)
        return files
    except FileNotFoundError:
        print(f"Error: Directory '{directory}' not found.")
        return []
    except PermissionError:
        print(f"Error: Permission denied to access '{directory}'.")
        return []

def search_files(directory, pattern):
    """Searches for files in the given directory matching the wildcard pattern."""
    try:
        files = os.listdir(directory)
        matching_files = []
        for file in files:
            if fnmatch.fnmatch(file, pattern):
                matching_files.append(os.path.join(directory, file))
        return matching_files
    except FileNotFoundError:
        print(f"Error: Directory '{directory}' not found.")
        return []
    except PermissionError:
        print(f"Error: Permission denied to access '{directory}'.")
        return []

def main():
    """Main function to run the file manager."""
    while True:
        print("\nFile Manager")
        print("1. List files")
        print("2. Search files")
        print("3. Exit")

        choice = input("Enter your choice: ")

        if choice == "1":
            directory = input("Enter directory (default: .): ") or "."
            files = list_files(directory)
            if files:
                print("Files and directories:")
                for file in files:
                    print(file)

        elif choice == "2":
            directory = input("Enter directory to search (default: .): ") or "."
            pattern = input("Enter search pattern (e.g., *.txt, image?.jpg): ")
            results = search_files(directory, pattern)
            if results:
                print("Matching files:")
                for file in results:
                    print(file)
            else:
                print("No matching files found.")

        elif choice == "3":
            print("Exiting...")
            break

        else:
            print("Invalid choice. Please try again.")

if __name__ == "__main__":
    main()
```

